query k8s_recommendation_summary($accountId:uuid!, $accountId2:String, $startDate: timestamp, $endDate: timestamp, $yesterdayStartDate: timestamp, $yesterdayEndDate: timestamp, $yearStartDate:timestamp, $yearEndDate:timestamp) {
  recommendation_aggregate: recommendation_groupings_v2(where: {account_id:{_eq:"a2a30b02-0f67-42e5-a2ab-c658230fd798"},category:{_eq:"RightSizing"},rule_name:{_eq:"pod_right_sizing"},status:{_in:["Open","InProgress"]}}){
    rows{
      count
      sum_estimated_savings
    }
  }
  recommendation_expense_aggregate:recommendation_groupings_v2(where: {account_id:{_eq:$accountId2},category:{_eq:"RightSizing"},rule_name:{_eq:"pod_right_sizing"},status:{_in:["Open","InProgress"]}, estimated_savings:{_lt:0} }){
    rows{
      count
      sum_estimated_savings
    }
  }  
  spends_aggregate(where:{cloud_account: {_eq:$accountId}, _and:[{date:{_gt:$startDate}}, {date:{_lt:$endDate}}, {exclude_aggregate: {_eq: false }}]}){
    aggregate{
      sum{
        amount
      }
    }
  }

  yesterday_spends_aggregate: spends_aggregate(where:{cloud_account: {_eq:$accountId}, _and:[{date:{_gt:$yesterdayStartDate}}, {date:{_lt:$yesterdayEndDate}} , {exclude_aggregate: {_eq: false }}]}){
    aggregate{
      sum{
        amount
      }
    }
  }

}

