query get_K8_cluster_data($accountId: uuid!, $accountId1: String, $startDate:timestamp, $endDate:timestamp, $lmStartDate:timestamp, $lmEndDate:timestamp, $yearStartDate:timestamp, $yearEndDate:timestamp, $todayStartDate: Datetime) {
  k8s_cluster_groupings: k8s_cluster_groupings_v2(where:{account_id:{_eq: $accountId1}}){
    rows{
      account_id
      node_count
      node_cpu_capacity
      node_cpu_allocatable
      node_memory_capacity
      node_memory_allocatable
      node_spot_count
      pod_status_counts
      workload_type_counts
    }
  }

  recommendation_aggregate: recommendation_groupings_v2(where: {account_id: {_eq: $accountId1}, status:{_in:["Open", "InProgess"]}, category: {_in: ["Configuration","RightSizing","K8sSpotRecommendation"]} }){
    rows{
      sum_estimated_savings
      count
    }
  }

  spends_aggregate(where:{cloud_account: {_eq:$accountId}, _and:[{date:{_gte:$startDate}}, {date:{_lte:$endDate}} , {exclude_aggregate: {_eq: false }}]}){
    aggregate{
      sum{
        amount
      }
    }
  }

  lm_spends_aggregate: spends_aggregate(where:{cloud_account: {_eq:$accountId}, _and:[{date:{_gte:$lmStartDate}}, {date:{_lte:$lmEndDate}} , {exclude_aggregate: {_eq: false }}]}){
    aggregate{
      sum{
        amount
      }
    }
  }
  yearly_spends_aggregate: spends_aggregate(where:{cloud_account: {_eq:$accountId}, _and:[{date:{_gte:$yearStartDate}}, {date:{_lte:$yearEndDate}}, {exclude_aggregate: {_eq: false }}]}){
    aggregate{
      sum{
        amount
      }
    }
  }

  events:  event_groupings_v2(group_by: ["tenant_id", "account_id", "aggregation_key"], where: {account_id: {_eq: $accountId1}, created_at:{_gte: $todayStartDate}}) {
    rows{
      aggregation_key
      event_count  
    }
  }
}

